-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "التاريخ الإسلامي" (tarikh-islami) — تستنفد العنقود بالكامل
-- (8 تصنيفات فرعية من أصل 8، كلها بلا محتوى): الخلفاء الراشدون، الدول
-- الإسلامية الكبرى، الأندلس، الحروب الصليبية والتتار، الدولة العثمانية،
-- تاريخ العلماء والمذاهب، الحضارة الإسلامية، القراءة النقدية للمصادر.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: تاريخ الخلفاء
-- للسيوطي، البداية والنهاية لابن كثير، نفح الطيب للمقري، الكامل في
-- التاريخ لابن الأثير، الدولة العثمانية عوامل النهوض وأسباب السقوط
-- لعلي محمد الصلابي، سير أعلام النبلاء للذهبي، أطلس تاريخ الإسلام
-- لحسين مؤنس، مقدمة ابن خلدون.
-- الآيات المستشهَد بها (النور:55، الزمر:9، الحجرات:6) تحقَّقت حرفياً
-- من artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah
-- قبل الإدراج.
-- الحديث الوحيد المستشهَد به «إن العلماء ورثة الأنبياء» (أبو داود
-- والترمذي، صححه الألباني) تحقَّق حرفياً عبر WebSearch قبل الإدراج.
-- حديثان آخران بُحث عنهما («الخلافة بعدي ثلاثون سنة» و«لتفتحن
-- القسطنطينية...») ولم يُدرَجا لاختلاف العلماء في تصحيحهما وتضعيف
-- بعضهم لهما (علة في الإسناد)، فاكتُفي بالوقائع التاريخية من المصادر
-- المسمّاة فقط دون فرض حديث غير موثَّق الدرجة بدقة.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الثمانية عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الخلفاء الراشدون
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ef51c67c-4c0a-4e75-ac5f-6b6144d2ba5a' AND title='الخلفاء الراشدون: سيرتهم ومنهجهم في الحكم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الخلفاء الراشدون: سيرتهم ومنهجهم في الحكم', 'تعريف موجز بالخلفاء الأربعة الراشدين وأبرز محطات عهد كل منهم في بناء الدولة الإسلامية الأولى', 'ef51c67c-4c0a-4e75-ac5f-6b6144d2ba5a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'من هم الخلفاء الراشدون', 'الخلفاء الراشدون هم أبو بكر الصديق وعمر بن الخطاب وعثمان بن عفان وعلي بن أبي طالب رضي الله عنهم، تولّوا خلافة المسلمين بعد وفاة النبي صلى الله عليه وسلم بالتتابع، وسُمّوا "راشدين" لسيرهم على منهج النبوة في العدل والشورى وسياسة الأمة.', 1),
    (v_lesson, 'timeline_events', 'أبرز محطات عهودهم', 'أبو بكر الصديق (11-13هـ) واجه حروب الردة فحفظ وحدة الدولة، وبدأ جمع القرآن في مصحف واحد بمشورة عمر وتنفيذ زيد بن ثابت. عمر بن الخطاب (13-23هـ) وسّع الدولة إلى فارس والشام ومصر، ونظّم الدواوين وأرّخ بالتقويم الهجري. عثمان بن عفان (23-35هـ) أتمّ توحيد المصحف على قراءة واحدة ووزّعه على الأمصار، ثم استُشهد في فتنة انتهت بتولي علي. علي بن أبي طالب (35-40هـ) واجه حروبًا داخلية (الجمل وصفّين) ونقل مركز الخلافة إلى الكوفة.', 2),
    (v_lesson, 'evidence', 'وعد الاستخلاف في الأرض', 'قال تعالى: ﴿وَعَدَ اللَّهُ الَّذِينَ آمَنُوا مِنكُمْ وَعَمِلُوا الصَّالِحَاتِ لَيَسْتَخْلِفَنَّهُمْ فِي الْأَرْضِ كَمَا اسْتَخْلَفَ الَّذِينَ مِن قَبْلِهِمْ﴾ (النور: 55)، وقد رأى كثير من المفسرين أن خلافة الراشدين من أبرز مصاديق هذا الوعد الإلهي.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تاريخ الخلفاء — جلال الدين السيوطي', 1),
    (v_lesson, 'book', 'البداية والنهاية — ابن كثير', 2);
  END IF;

  -- 2) الدول الإسلامية الكبرى
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='adc99249-23f9-4ff7-a191-560d0b96ebdb' AND title='الدولة الأموية والعباسية: أبرز محطات الدول الإسلامية الكبرى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الدولة الأموية والعباسية: أبرز محطات الدول الإسلامية الكبرى', 'نظرة موجزة على قيام الدولتين الأموية والعباسية وأبرز إنجازاتهما وأسباب زوالهما', 'adc99249-23f9-4ff7-a191-560d0b96ebdb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الدولة الأموية', 'أسّس معاوية بن أبي سفيان الدولة الأموية سنة 41هـ (عام الجماعة) بعد تنازل الحسن بن علي عن الخلافة له، واتخذ دمشق عاصمة. اتسعت الدولة غربًا حتى الأندلس وشرقًا حتى السند وبلاد ما وراء النهر، وانتهت سنة 132هـ على يد الثورة العباسية بقيادة أبي العباس السفاح.', 1),
    (v_lesson, 'timeline_events', 'الدولة العباسية', 'قامت الدولة العباسية سنة 132هـ، واتخذت بغداد عاصمة لها بعد أن بناها الخليفة أبو جعفر المنصور سنة 145هـ. بلغت أوج ازدهارها الحضاري في عهدي هارون الرشيد والمأمون، ومن أبرز معالمها بيت الحكمة الذي كان مركزًا لحركة الترجمة والعلوم. انتهت الخلافة العباسية في بغداد سنة 656هـ بسقوطها على يد المغول.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'البداية والنهاية — ابن كثير', 1);
  END IF;

  -- 3) الأندلس
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='51f09c81-74a5-4ac1-9d1a-f99a49760257' AND title='فتح الأندلس وحضارتها الزاهرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فتح الأندلس وحضارتها الزاهرة', 'نظرة موجزة على فتح الأندلس وقيام إمارتها ثم خلافتها وازدهارها الحضاري إلى سقوط غرناطة', '51f09c81-74a5-4ac1-9d1a-f99a49760257', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الفتح وقيام الإمارة', 'فُتحت الأندلس سنة 92هـ بقيادة طارق بن زياد في عهد الخليفة الأموي الوليد بن عبد الملك، بعد هزيمة الملك القوطي رودريك في موقعة وادي لكة. ثم أسّس عبد الرحمن الداخل الإمارة الأموية في الأندلس سنة 138هـ بعد فراره من ملاحقة العباسيين، واتخذ قرطبة عاصمة لها.', 1),
    (v_lesson, 'timeline_events', 'الخلافة والازدهار والسقوط', 'أعلن عبد الرحمن الناصر قيام الخلافة الأموية في قرطبة سنة 316هـ، فبلغت الأندلس عصرها الذهبي علمًا وعمرانًا، ومن معالمها جامع قرطبة الكبير ومكتباتها الحافلة وعلماؤها كابن رشد وابن حزم. تفككت الدولة لاحقًا إلى ممالك الطوائف، وانتهى الوجود الإسلامي السياسي فيها بسقوط غرناطة سنة 897هـ على يد أبي عبد الله محمد الثاني عشر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'نفح الطيب من غصن الأندلس الرطيب — أحمد بن محمد المقري التلمساني', 1);
  END IF;

  -- 4) الحروب الصليبية والتتار
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2f119c46-44ac-4997-a2c6-2bfde21345a9' AND title='الحروب الصليبية وغزو التتار: صمود الأمة واسترداد المبادرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الحروب الصليبية وغزو التتار: صمود الأمة واسترداد المبادرة', 'نظرة موجزة على الحملات الصليبية وغزو المغول وكيف استردت الأمة الإسلامية زمام المبادرة في المعركتين', '2f119c46-44ac-4997-a2c6-2bfde21345a9', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الحروب الصليبية', 'انطلقت الحملة الصليبية الأولى من أوروبا سنة 489هـ، فاحتل الصليبيون بيت المقدس سنة 492هـ. تصدّى لهم القادة المسلمون بالتدريج، من عماد الدين زنكي ونور الدين محمود، حتى استرد صلاح الدين الأيوبي بيت المقدس بعد انتصاره الحاسم في معركة حطين سنة 583هـ. استمرت الحروب نحو قرنين، وانتهى الوجود الصليبي في الشام بسقوط عكا سنة 690هـ على يد المماليك.', 1),
    (v_lesson, 'timeline_events', 'غزو التتار ومعركة عين جالوت', 'اجتاح المغول بقيادة هولاكو بغداد وأسقطوا الخلافة العباسية فيها سنة 656هـ في مجزرة كبرى. تقدّم المغول نحو الشام، فتصدى لهم المماليك بقيادة السلطان قطز والأمير بيبرس وحقّقوا انتصارًا حاسمًا عليهم في معركة عين جالوت سنة 658هـ، وكانت أول هزيمة كبرى توقف زحف المغول غربًا.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'البداية والنهاية — ابن كثير', 1),
    (v_lesson, 'book', 'الكامل في التاريخ — عز الدين ابن الأثير', 2);
  END IF;

  -- 5) الدولة العثمانية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='03b0dd57-8e2b-4e1c-8e6d-af300560e2aa' AND title='الدولة العثمانية: النشأة والتوسع وفتح القسطنطينية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الدولة العثمانية: النشأة والتوسع وفتح القسطنطينية', 'نظرة موجزة على نشأة الدولة العثمانية وتوسعها وفتحها للقسطنطينية إلى إلغاء الخلافة فيها', '03b0dd57-8e2b-4e1c-8e6d-af300560e2aa', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'النشأة والتوسع', 'أسّس عثمان بن أرطغرل الدولة العثمانية في الأناضول نحو سنة 699هـ، فتوسعت في عهد خلفائه حتى غدت إمبراطورية عابرة للقارات. فتح السلطان محمد الثاني (الفاتح) القسطنطينية سنة 857هـ منهيًا الدولة البيزنطية، وأصبحت إسطنبول عاصمة للدولة. ثم ضمّ السلطان سليم الأول الشام ومصر والحجاز سنتي 922-923هـ.', 1),
    (v_lesson, 'timeline_events', 'العصر الذهبي والزوال', 'بلغت الدولة أوج قوتها في عهد السلطان سليمان القانوني في القرن العاشر الهجري (السادس عشر الميلادي)، ممتدة عبر ثلاث قارات. أُلغيت الخلافة العثمانية رسميًا سنة 1342هـ (1924م) بقرار من الجمعية الوطنية التركية الكبرى.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الدولة العثمانية: عوامل النهوض وأسباب السقوط — علي محمد الصلابي', 1);
  END IF;

  -- 6) تاريخ العلماء والمذاهب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='16637154-7176-4bca-9c4a-b5f15714ff1e' AND title='نشأة المذاهب الفقهية الأربعة وأئمتها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('نشأة المذاهب الفقهية الأربعة وأئمتها', 'تعريف موجز بأئمة المذاهب الفقهية السنية الأربعة وأبرز آثارهم العلمية وسياق نشأة مذاهبهم', '16637154-7176-4bca-9c4a-b5f15714ff1e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أئمة المذاهب الأربعة', 'برزت المذاهب الفقهية السنية الأربعة في القرنين الثاني والثالث الهجريين استجابة لحاجة الأمة المتوسعة إلى تقعيد استنباط الأحكام: الإمام أبو حنيفة النعمان (ت 150هـ) في الكوفة، والإمام مالك بن أنس (ت 179هـ) في المدينة صاحب "الموطأ"، والإمام محمد بن إدريس الشافعي (ت 204هـ) الذي جمع بين فقه الحجاز والعراق وأسّس علم أصول الفقه في كتابه "الرسالة"، والإمام أحمد بن حنبل (ت 241هـ) في بغداد صاحب "المسند".', 1),
    (v_lesson, 'evidence', 'منزلة العلماء', 'عن أبي الدرداء رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «إِنَّ الْعُلَمَاءَ وَرَثَةُ الْأَنْبِيَاءِ، وَإِنَّ الْأَنْبِيَاءَ لَمْ يُوَرِّثُوا دِينَارًا وَلَا دِرْهَمًا، إِنَّمَا وَرَّثُوا الْعِلْمَ»، رواه أبو داود والترمذي وصححه الألباني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'سير أعلام النبلاء — شمس الدين الذهبي', 1);
  END IF;

  -- 7) الحضارة الإسلامية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2f6d2952-7628-44e7-874b-a4c536cd6c0d' AND title='روافد الحضارة الإسلامية وإسهاماتها العلمية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('روافد الحضارة الإسلامية وإسهاماتها العلمية', 'نظرة موجزة على حركة الترجمة والعلوم في الحضارة الإسلامية وأبرز علمائها الذين أثروا الفكر الإنساني', '2f6d2952-7628-44e7-874b-a4c536cd6c0d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'حركة الترجمة والعلوم', 'قامت الحضارة الإسلامية على تعظيم طلب العلم، فأنشأ العباسيون "بيت الحكمة" في بغداد مركزًا لترجمة علوم اليونان والفرس والهند، ونبغ فيها علماء تركوا أثرًا عالميًا: الخوارزمي (واضع علم الجبر ومصدر كلمة "الخوارزمية")، وابن الهيثم (رائد المنهج التجريبي في علم البصريات)، وابن سينا (صاحب "القانون في الطب")، والرازي والبيروني في الطب والفلك.', 1),
    (v_lesson, 'evidence', 'فضل العلم في القرآن', 'قال تعالى: ﴿قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لَا يَعْلَمُونَ إِنَّمَا يَتَذَكَّرُ أُولُو الْأَلْبَابِ﴾ (الزمر: 9)، وهذا الفضل المعنوي للعلم كان أحد الروافد التي دفعت الحضارة الإسلامية إلى الازدهار العلمي.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أطلس تاريخ الإسلام — حسين مؤنس', 1);
  END IF;

  -- 8) القراءة النقدية للمصادر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5ad2e3e2-5551-4b2d-a36a-ade1bdee8aaf' AND title='منهج النقد التاريخي عند المسلمين: التثبت من الأخبار') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج النقد التاريخي عند المسلمين: التثبت من الأخبار', 'تعريف موجز بمنهج النقد التاريخي عند المسلمين وأصله القرآني في التثبت من الأخبار قبل قبولها', '5ad2e3e2-5551-4b2d-a36a-ade1bdee8aaf', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'منهج ابن خلدون في نقد الأخبار', 'نقل المؤرخون المسلمون مناهج علم الحديث في نقد الإسناد (الجرح والتعديل) إلى ميدان نقد الأخبار التاريخية. وقد أرسى ابن خلدون في "مقدمته" قواعد منهجية لتمحيص الأخبار، منها مطابقة الخبر لطبائع الاجتماع البشري الممكنة، والحذر من المبالغة والتحريف، ورد الخبر إذا خالف قوانين العمران المعروفة، تمييزًا للحقيقة التاريخية عن الأساطير والروايات المصطنعة.', 1),
    (v_lesson, 'evidence', 'أصل التثبت في القرآن', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِن جَاءَكُمْ فَاسِقٌ بِنَبَإٍ فَتَبَيَّنُوا أَن تُصِيبُوا قَوْمًا بِجَهَالَةٍ فَتُصْبِحُوا عَلَىٰ مَا فَعَلْتُمْ نَادِمِينَ﴾ (الحجرات: 6)، وهذه الآية أصل قرآني لوجوب التثبت من الأخبار قبل نقلها أو البناء عليها، وهو ما استند إليه المنهج النقدي عند مؤرخي المسلمين.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مقدمة ابن خلدون — عبد الرحمن ابن خلدون', 1);
  END IF;

